import ActivityArea from "~/components/activityArea";
import { directive } from "vue-awesome-swiper";
import { paramsToStr } from "~/utils/tools";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  components: {
    ActivityArea,
  },
  directives: {
    swiper: directive,
  },
  async asyncData({ $get,store }) {
    const banner = $get("ad/lists", { params: { pid: 2, client: 2 } });
    const index = $get("pc/index");
    const { data: bannerList } = await banner;
    const { data: indexData } = await index;
    let couponList = []
    if(store.getters.isLogin) {
      const { data } = await $get("coupon/registerSendCoupon");
      couponList = data
    }
    return { bannerList, indexData, couponList, };
  },
  data() {
    const self = this;
    return {
      bannerList: [],
      showCoupon: false,
      swiperOptions: {
        pagination: {
          el: ".swiper-pagination"
        },
        navigation: {
          nextEl: ".swiper-button-next",
          prevEl: ".swiper-button-prev",
        },
        width: 1020,
        preventClicks: true,
        loop: true,
        observer:true,//修改swiper自己或子元素时，自动初始化swiper 
        observeParents:true,//修改swiper的父元素时，自动初始化swiper 
        on: {
          slideChangeTransitionStart() {
            console.log(this.activeIndex, 'active', this.realIndex)
            console.log(this.isEnd, 'isBegin', this.isBeginning)
            if(this.isEnd) {
              // 到达第4个
              this.slideToLoop(0)
            }
            if(this.isBeginning) {
              this.slideTo(self.bannerList.length)
              
            }
          },
        }
      },
    };
  },
  created() {
    // console.log(this);
  },
  mounted() {
    // if(this.$refs.mySwiper) {
      
    // }
  },
  // activated() {
  //   this.mySwiper.updateSwiper()
  // },
  beforeDestroy() {
    // console.log(this.mySwiper, "##");
    // this.bannerList = false;
    // this.mySwiper.destroySwiper()
  },
  destroyed() {
  },
  computed: {
    mySwiper() {
      return this.$refs.mySwiper;   
    }
  },
  methods: {
  },
  watch:{
    couponList: {
      immediate: true,
      handler(val) {
        if(val.length) {
          this.showCoupon = true
          this.$store.dispatch('getPublicData')
        }
      },
    },
  }
};
